      </div>
    </section>
  );
}
```

**Individual item rendering**:
```typescript
function WorkItemSuggestion(props: WorkItemSuggestionProps) {
  const [status, setStatus] = useState<WorkItemStatus>("pending");

  async function handleAccept() {
    setStatus("accepting");
    await acceptWorkItem(workspaceId, props);  // POST to accept endpoint
    setStatus("accepted");
  }

  return (
    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
      <div className="work-item-suggestion-header">
        <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
        {props.category && <CategoryBadge category={props.category} />}
        {props.priority && <span className="work-item-priority">{props.priority}</span>}
        <div className="work-item-actions">
          <button className="work-item-btn work-item-btn--accept" onClick={handleAccept}>Accept</button>
          <button className="work-item-btn work-item-btn--dismiss" onClick={handleDismiss}>Dismiss</button>
        </div>
      </div>
      <p className="entity-name">{props.title}</p>
      <p className="work-item-rationale">{props.rationale}</p>
      {isDuplicate && <p className="work-item-duplicate-hint">Similar to existing: {props.possibleDuplicateName} ({similarity}% match)</p>}
      {props.project && <p className="work-item-project">Project: {props.project}</p>}
    </article>
  );
}
```

**Flow**:
1. PM agent returns `{ suggestions: [...], updated: [...], discarded: [...] }`
2. Chat agent renders suggestions as `WorkItemSuggestionList` component
3. User clicks "Accept All" or individual "Accept" buttons
4. Client calls `POST /api/workspaces/:workspaceId/work-items/accept`
5. Endpoint creates task/feature/project in DB
6. Item UI shows "Accepted" badge

---

### 5. **Tests for PM Agent Functionality**

#### **Smoke Test: PM Agent Task Creation** (`tests/smoke/pipeline.test.ts`, lines 133–187)
```typescript
it("PM agent creates task from explicit request", async () => {
  const { baseUrl, surreal } = getRuntime();
  const workspace = await createOnboardedWorkspace(baseUrl, surreal);

  // Seed a project first
  const projectRecord = new RecordId("project", randomUUID());
  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
  await surreal.create(projectRecord).content({
    name: "Brain Platform",
    status: "active",
    workspace: workspaceRecord,
    created_at: new Date(),
    updated_at: new Date(),
  });
  await surreal.relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
    added_at: new Date(),
  }).output("after");

  // Send explicit creation request
  const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
    method: "POST",
    body: JSON.stringify({
      clientMessageId: randomUUID(),
      workspaceId: workspace.workspaceId,
      conversationId: workspace.conversationId,
      text: "Add a task for implementing user authentication for Brain Platform.",
    }),
  });

  const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 120_000);
  const assistantEvent = events.find((event) => event.type === "assistant_message");

  // Verify task created OR suggestion rendered
  const [taskRows] = await surreal.query<[Array<{id, title}>]>(
    "SELECT id, title FROM task WHERE workspace = $workspace;",
    { workspace: workspaceRecord },
  ).collect();

  const hasTaskInDb = taskRows.length > 0;
  const hasSuggestionInResponse = assistantEvent.text.includes("WorkItemSuggestionList");
  expect(hasTaskInDb || hasSuggestionInResponse).toBe(true);
});
```

**What it tests**:
- Chat agent interprets explicit creation request ("Add a task...")
- Either creates task directly in DB via PM agent's `create_work_item` tool
- OR returns PM suggestions as `WorkItemSuggestionList` for user acceptance
- Verifies task created in workspace scope

**No unit tests** found specifically for PM agent (only smoke test exists).

---

### 6. **`ChatAgentToolDeps` vs `ChatToolDeps` — Type Difference**

#### **`ChatToolDeps`** (`chat/tools/types.ts`, lines 12–19)
```typescript
export type ChatToolDeps = {
  surreal: Surreal;
  embeddingModel: any;
  embeddingDimension: number;
  extractionModelId: string;
  extractionModel: any;
  extractionStoreThreshold: number;
};
```
**Used by**: Shared chat tools (search, get_project_status, create_observation) and PM tools

#### **`ChatAgentToolDeps`** (`chat/tools/types.ts`, lines 21–23)
```typescript
export type ChatAgentToolDeps = ChatToolDeps & {
  pmModel: any;
};
```
**Used by**: Chat agent tools (includes PM subagent invocation)

#### **Why This Distinction?**

| Context | Deps Type | Why |
|---------|-----------|-----|
| **Chat agent** (main orchestrator) | `ChatAgentToolDeps` | Needs `pmModel` to invoke subagent |
| **PM agent** (subagent) | `ChatToolDeps` | Gets `pmModel` from caller via `input.deps.pmModel` |
| **Shared tools** (search, status, etc.) | `ChatToolDeps` | Don't need to invoke subagents |
| **Work item accept endpoint** | Uses `ServerDependencies` | Different context (HTTP handler) |

**Key insight**: 
- `ChatToolDeps` is the **minimal set** all tools need (surreal, embeddings, extraction model)
- `ChatAgentToolDeps` adds `pmModel` for the **chat agent specifically** (because only chat agent invokes PM)
- **PM agent doesn't need `ChatAgentToolDeps`**—it receives `ChatToolDeps & { pmModel }` from caller
- This prevents circular dependency: PM agent (subagent) doesn't import chat agent types

**Why PM tool signature is `ChatToolDeps` not `ChatAgentToolDeps`**:
```typescript
// In agents/pm/agent.ts, line 52:
export type PmAgentInput = {
  deps: ChatToolDeps & { pmModel: any };  // <-- inline the pmModel, don't use ChatAgentToolDeps
  context: ChatToolExecutionContext;
  // ...
};

// In agents/pm/tools.ts, line 8:
export function createPmTools(deps: ChatToolDeps) {  // <-- just ChatToolDeps
  // PM tools use search, status, create_observation (all in ChatToolDeps)
  // PM also has create_work_item which needs extractionModel (in ChatToolDeps)
}

// But PM agent signature accepts pmModel via inline union:
export async function runPmAgent(input: PmAgentInput): Promise<PmAgentOutput> {
  const result = await generateText({
    model: input.deps.pmModel,  // <-- pmModel is in input.deps, not direct import
    // ...
  });
}
```

**Architecture benefit**: Keeps PM agent **decoupled from chat agent types**. PM agent only knows about `ChatToolDeps` + the inline pmModel, not `ChatAgentToolDeps`.

---

### **Summary Diagram**

```
┌─────────────────────────────────────────────────────────────────┐
│                     Server Bootstrap                             │
├─────────────────────────────────────────────────────────────────┤
│ ENV: PM_MODEL (optional, falls back to EXTRACTION_MODEL)         │
│   ↓                                                               │
│ config.pmModelId                                                 │
│   ↓                                                               │
│ runtime.pmModel = openrouter(config.pmModelId)                   │
│   ↓                                                               │
│ ServerDependencies.pmModel                                        │
└─────────────────────────────────────────────────────────────────┘

┌─────────────────────────────────────────────────────────────────┐
│                    Chat Message Flow                              │
├─────────────────────────────────────────────────────────────────┤
│ processChatMessage(deps: ServerDependencies)                      │
│   ↓                                                               │
│ runChatAgent(pmModel: deps.pmModel)                               │
│   ↓                                                               │
│ createChatAgentTools(deps: ChatAgentToolDeps)                     │
│   ├─→ search_entities (ChatToolDeps)                              │
│   ├─→ get_project_status (ChatToolDeps)                           │
│   ├─→ create_observation (ChatToolDeps)                           │
│   ├─→ create_provisional_decision (ChatToolDeps)                  │
│   ├─→ create_question (ChatToolDeps)                              │
│   └─→ invoke_pm_agent (ChatAgentToolDeps)                         │
│         ↓                                                          │
│         runPmAgent(deps: ChatToolDeps & {pmModel})                │
│           ├─→ createPmTools(ChatToolDeps)                         │
│           │   ├─→ search_entities                                 │
│           │   ├─→ get_project_status                              │
│           │   ├─→ create_observation                              │
│           │   ├─→ suggest_work_items   ← Triage/dedup, no persist │
│           │   └─→ create_work_item     ← Direct creation          │
│           └─→ generateText(model: pmModel)                        │
│               ↓                                                    │
│               { summary, suggestions, updated, discarded, ... }   │
│                 ↓                                                  │
│               Chat agent renders WorkItemSuggestionList           │
│                 ↓                                                  │
│               User clicks "Accept" / "Accept All"                 │
│                 ↓                                                  │
│               POST /api/workspaces/:workspaceId/work-items/accept │
│                 ↓                                                  │
│               Create task/feature/project in DB                   │
└─────────────────────────────────────────────────────────────────┘
```

---

### **Key Files Reference**

| File Path | Purpose | Key exports |
|-----------|---------|-------------|
| `app/src/server/agents/pm/agent.ts` | PM agent orchestration | `runPmAgent()`, `PmAgentOutput`, `WorkItemSuggestion` |
| `app/src/server/agents/pm/prompt.ts` | Dynamic system prompt | `buildPmSystemPrompt()` |
| `app/src/server/agents/pm/tools.ts` | PM tool factory | `createPmTools()` |
| `app/src/server/agents/pm/suggest-work-items.ts` | Batch dedup/triage | `createSuggestWorkItemsTool()` |
