 34→  workspaceOwnerRecord?: RecordId<"person", string>;
 35→  inheritedEntityIds?: RecordId[];
 36→  messages: ConversationMessage[];
 37→  isOnboarding?: boolean;
 38→  onboardingState?: OnboardingState;
 39→  onToken: (token: string) => Promise<void> | void;
 40→}): Promise<ChatAgentResult> {
 41→  const context = await buildChatContext({
 42→    surreal: input.surreal,
 43→    conversationRecord: input.conversationRecord,
 44→    workspaceRecord: input.workspaceRecord,
 45→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 46→      ? { inheritedEntityIds: input.inheritedEntityIds }
 47→      : {}),
 48→  });
 49→
 50→  const system = buildSystemPrompt(context, {
 51→    isOnboarding: input.isOnboarding,
 52→    onboardingState: input.onboardingState,
 53→  });
 54→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 55→    role: message.role,
 56→    content: message.text,
 57→  }));
 58→
 59→  const result = streamText({
 60→    model: input.model,
 61→    system,
 62→    messages: modelMessages,
 63→    tools: createChatAgentTools({
 64→      surreal: input.surreal,
 65→      pmModel: input.pmModel,
 66→      embeddingModel: input.embeddingModel,
 67→      embeddingDimension: input.embeddingDimension,
 68→      extractionModelId: input.extractionModelId,
 69→      extractionModel: input.extractionModel,
 70→      extractionStoreThreshold: input.extractionStoreThreshold,
 71→    }),
 72→    experimental_context: {
 73→      actor: "chat_agent",
 74→      workspaceRecord: input.workspaceRecord,
 75→      conversationRecord: input.conversationRecord,
 76→      currentMessageRecord: input.currentMessageRecord,
 77→      latestUserText: input.latestUserText,
 78→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 79→    },
 80→    stopWhen: stepCountIs(5),
 81→  });
 82→
 83→  let text = "";
 84→  const collectedEntities: CollectedEntity[] = [];
 85→  const collectedRelationships: CollectedRelationship[] = [];
 86→
 87→  for await (const part of result.fullStream) {
 88→    if (part.type === "text-delta") {
 89→      text = `${text}${part.text}`;
 90→      await input.onToken(part.text);
 91→      continue;
 92→    }
 93→
 94→    if (part.type === "tool-result") {
 95→      const toolResult = part.output as Record<string, unknown> | undefined;
 96→      if (toolResult) {
 97→        if (Array.isArray(toolResult.extracted_entities)) {
 98→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
 99→        }
100→        if (Array.isArray(toolResult.extracted_relationships)) {
101→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
102→        }
103→      }
104→    }
105→  }
106→
107→  if (text.trim().length === 0) {
108→    text = await result.text;
109→  }
110→
111→  return {
112→    text: text.trim(),
113→    collectedEntities,
114→    collectedRelationships,
115→  };
116→}
