 66→      item.title,
 67→      deps.config.embeddingDimension,
 68→    );
 69→
 70→    const entityId = randomUUID();
 71→
 72→    if (item.kind === "task") {
 73→      const taskRecord = new RecordId("task", entityId);
 74→      await deps.surreal.create(taskRecord).content({
 75→        title: item.title,
 76→        status: "open",
 77→        workspace: workspaceRecord,
 78→        ...(item.category ? { category: item.category } : {}),
 79→        ...(item.priority ? { priority: item.priority } : {}),
 80→        ...(embedding ? { embedding } : {}),
 81→        created_at: now,
 82→        updated_at: now,
 83→      });
 84→
 85→      if (item.project) {
 86→        try {
 87→          const projectRecord = await resolveWorkspaceProjectRecord({
 88→            surreal: deps.surreal,
 89→            workspaceRecord,
 90→            projectInput: item.project,
 91→          });
 92→          await deps.surreal
 93→            .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
 94→              added_at: now,
 95→            })
 96→            .output("after");
 97→        } catch {
 98→          // project resolution is best-effort; task still created
 99→        }
100→      }
101→
102→      void seedDescriptionEntry({
103→        surreal: deps.surreal,
104→        targetRecord: taskRecord,
105→        text: item.rationale,
106→      }).catch(() => undefined);
107→
108→      logInfo("work-item.accept.task.created", "Task created from work item suggestion", {
109→        workspaceId,
110→        entityId,
111→        title: item.title,
112→      });
113→
114→      return jsonResponse({ entityId: `task:${entityId}` }, 201);
115→    }
116→
117→    if (item.kind === "project") {
118→      const projectRecord = await createProjectRecord({
119→        surreal: deps.surreal,
120→        name: item.title,
121→        status: "active",
122→        now,
123→        workspaceRecord,
124→      });
125→
126→      if (embedding) {
127→        await deps.surreal.update(projectRecord).merge({ embedding });
128→      }
129→
130→      void seedDescriptionEntry({
131→        surreal: deps.surreal,
132→        targetRecord: projectRecord,
133→        text: item.rationale,
134→      }).catch(() => undefined);
135→
136→      logInfo("work-item.accept.project.created", "Project created from work item suggestion", {
137→        workspaceId,
138→        entityId: projectRecord.id as string,
139→        title: item.title,
140→      });
141→
142→      return jsonResponse({ entityId: `project:${projectRecord.id as string}` }, 201);
143→    }
144→
145→    // feature
146→    const featureRecord = new RecordId("feature", entityId);
147→    await deps.surreal.create(featureRecord).content({
148→      name: item.title,
149→      status: "active",
150→      ...(item.category ? { category: item.category } : {}),
151→      ...(embedding ? { embedding } : {}),
152→      created_at: now,
153→      updated_at: now,
154→    });
155→
156→    if (item.project) {
157→      try {
158→        const projectRecord = await resolveWorkspaceProjectRecord({
159→          surreal: deps.surreal,
160→          workspaceRecord,
161→          projectInput: item.project,
162→        });
163→        await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
164→
165→        void fireDescriptionUpdates({
166→          surreal: deps.surreal,
167→          extractionModel: deps.extractionModel,
168→          trigger: {
169→            kind: "feature_created",
170→            entity: featureRecord,
171→            summary: `Feature added: ${item.title}`,
172→          },
173→        }).catch(() => undefined);
174→      } catch {
175→        // project resolution is best-effort; feature still created
176→      }
177→    }
178→
179→    void seedDescriptionEntry({
180→      surreal: deps.surreal,
181→      targetRecord: featureRecord,
182→      text: item.rationale,
183→    }).catch(() => undefined);
184→
185→    logInfo("work-item.accept.feature.created", "Feature created from work item suggestion", {
186→      workspaceId,
187→      entityId,
188→      title: item.title,
189→    });
190→
191→    return jsonResponse({ entityId: `feature:${entityId}` }, 201);
192→  } catch (error) {
193→    logError("work-item.accept.failed", "Failed to accept work item", error, {
194→      workspaceId,
195→      kind: item.kind,
196→      title: item.title,
197→    });
198→    const message = error instanceof Error ? error.message : "work item accept failed";
199→    return jsonError(message, 500);
200→  }
201→}
