60→    stream: processUIMessageStream({
61→      stream,
62→      runUpdateMessageJob(
63→        job: (options: {
64→          state: StreamingUIMessageState<UI_MESSAGE>;
65→          write: () => void;
66→        }) => Promise<void>,
67→      ) {
