69→          state,
70→          write: () => {
71→            controller?.enqueue(structuredClone(state.message));
72→          },
73→        });
74→      },
75→      onError: handleError,
76→    }),
77→    onError: handleError,
78→  }).finally(() => {
79→    // Only close if no error occurred. Calling close() on an errored controller
