  1→import { generateText, Output, stepCountIs } from "ai";
  2→import { z } from "zod";
  3→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES, type ExtractedEntity, type ExtractedRelationship } from "../../../shared/contracts";
  4→import type { ChatToolDeps, ChatToolExecutionContext } from "../../chat/tools/types";
  5→import { buildPmSystemPrompt } from "./prompt";
  6→import { createPmTools } from "./tools";
  7→
  8→const workItemSuggestionSchema = z.object({
  9→  kind: z.enum(["task", "feature", "project"]),
 10→  title: z.string().min(1),
 11→  rationale: z.string().min(1),
 12→  category: z.enum(ENTITY_CATEGORIES).optional(),
 13→  project: z.string().optional(),
 14→  priority: z.enum(ENTITY_PRIORITIES).optional(),
 15→  possible_duplicate: z
 16→    .object({
 17→      id: z.string().min(1),
 18→      name: z.string().min(1),
 19→      similarity: z.number().min(0).max(1),
 20→    })
 21→    .optional(),
 22→});
 23→
 24→const pmAgentResultSchema = z.object({
 25→  summary: z.string().min(1),
 26→  suggestions: z.array(workItemSuggestionSchema),
 27→  updated: z.array(
 28→    z.object({
 29→      existing_id: z.string().min(1),
 30→      title: z.string().min(1),
 31→      changes: z.string().min(1),
 32→    }),
 33→  ),
 34→  discarded: z.array(
 35→    z.object({
 36→      title: z.string().min(1),
 37→      reason: z.string().min(1),
 38→    }),
 39→  ),
 40→  observations_created: z.array(z.string().min(1)),
 41→});
 42→
 43→export type WorkItemSuggestion = z.infer<typeof workItemSuggestionSchema>;
 44→export type PmAgentResult = z.infer<typeof pmAgentResultSchema>;
 45→
 46→export type PmAgentOutput = PmAgentResult & {
 47→  extracted_entities: ExtractedEntity[];
 48→  extracted_relationships: ExtractedRelationship[];
 49→};
 50→
 51→export type PmAgentInput = {
 52→  deps: ChatToolDeps & { pmModel: any };
 53→  context: ChatToolExecutionContext;
 54→  intent: "plan_work" | "check_status" | "organize" | "track_dependencies";
 55→  conversationContext: string;
 56→  project?: string;
 57→};
 58→
 59→const INTENT_INSTRUCTIONS: Record<PmAgentInput["intent"], string> = {
 60→  check_status: "Primary action: call get_project_status when a project scope is available.",
 61→  plan_work: "Primary action: propose tasks/features/projects with suggest_work_items or create_work_item, deduping each item.",
 62→  track_dependencies: "Primary action: identify blockers/dependencies and create observations for high-risk paths.",
 63→  organize: "Primary action: organize work into clear, deduplicated next steps.",
 64→};
 65→
 66→export async function runPmAgent(input: PmAgentInput): Promise<PmAgentOutput> {
 67→  const system = await buildPmSystemPrompt({
 68→    surreal: input.deps.surreal,
 69→    workspaceRecord: input.context.workspaceRecord,
 70→  });
 71→
 72→  const result = await generateText({
 73→    model: input.deps.pmModel,
 74→    system,
 75→    prompt: [
 76→      "You are handling a PM request.",
 77→      `Intent: ${input.intent}`,
 78→      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
 79→      INTENT_INSTRUCTIONS[input.intent],
 80→      "Context:",
 81→      input.conversationContext,
 82→    ].join("\n"),
 83→    tools: createPmTools(input.deps),
 84→    output: Output.object({ schema: pmAgentResultSchema }),
 85→    experimental_context: input.context,
 86→    stopWhen: stepCountIs(6),
 87→  });
 88→
 89→  if (!result.output) {
 90→    throw new Error("pm agent did not produce structured output");
 91→  }
 92→
 93→  const extracted_entities: ExtractedEntity[] = [];
 94→  const extracted_relationships: ExtractedRelationship[] = [];
 95→
 96→  for (const step of result.steps) {
 97→    for (const toolResult of step.toolResults) {
 98→      const res = toolResult.output as Record<string, unknown> | undefined;
 99→      if (res) {
100→        if (Array.isArray(res.extracted_entities)) {
101→          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
102→        }
103→        if (Array.isArray(res.extracted_relationships)) {
104→          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
105→        }
106→      }
107→    }
108→  }
109→
110→  return {
111→    ...result.output,
112→    extracted_entities,
113→    extracted_relationships,
114→  };
115→}
116→

