  1→import { tool } from "ai";
  2→import { z } from "zod";
  3→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES, type EntityCategory } from "../../../shared/contracts";
  4→import { createEmbeddingVector } from "../../graph/embeddings";
  5→import { resolveWorkspaceProjectRecord, searchEntitiesByEmbedding } from "../../graph/queries";
  6→import { requireToolContext } from "../../chat/tools/helpers";
  7→import type { ChatToolDeps } from "../../chat/tools/types";
  8→
  9→type SuggestedWorkItem = {
 10→  kind: "task" | "feature" | "project";
 11→  title: string;
 12→  rationale: string;
 13→  category?: EntityCategory;
 14→  project?: string;
 15→  priority?: string;
 16→  possible_duplicate?: {
 17→    id: string;
 18→    name: string;
 19→    similarity: number;
 20→  };
 21→};
 22→
 23→type UpdatedWorkItem = {
 24→  existing_id: string;
 25→  title: string;
 26→  changes: string;
 27→};
 28→
 29→type DiscardedWorkItem = {
 30→  title: string;
 31→  reason: string;
 32→};
 33→
 34→const CLOSED_STATUSES = new Set(["done", "completed", "closed", "resolved", "superseded"]);
 35→
 36→export function createSuggestWorkItemsTool(deps: ChatToolDeps) {
 37→  return tool({
 38→    description:
 39→      "Process a batch of proposed work items and return issue-style PM triage buckets: suggestions, updated, discarded.",
 40→    inputSchema: z.object({
 41→      items: z.array(
 42→        z.object({
 43→          kind: z.enum(["task", "feature", "project"]).describe("Work item kind"),
 44→          title: z.string().min(1).describe("Concise work item title"),
 45→          rationale: z.string().min(1).describe("Why this work item is needed"),
 46→          category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional work item category"),
 47→          project: z.string().optional().describe("Optional project scope"),
 48→          priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important. medium: normal. low: nice-to-have."),
 49→        }),
 50→      ).min(1).max(25),
 51→    }),
 52→    execute: async (input, options) => {
 53→      const context = requireToolContext(options);
 54→      const suggestions: SuggestedWorkItem[] = [];
 55→      const updated: UpdatedWorkItem[] = [];
 56→      const discarded: DiscardedWorkItem[] = [];
 57→
 58→      for (const item of input.items) {
 59→        const suggestion: SuggestedWorkItem = {
 60→          kind: item.kind,
 61→          title: item.title,
 62→          rationale: item.rationale,
 63→          ...(item.category ? { category: item.category } : {}),
 64→          ...(item.project ? { project: item.project } : {}),
 65→          ...(item.priority ? { priority: item.priority } : {}),
 66→        };
 67→
 68→        const embedding = await createEmbeddingVector(deps.embeddingModel, item.title, deps.embeddingDimension);
 69→        if (!embedding) {
 70→          throw new Error("failed to create embedding for suggest_work_items");
 71→        }
 72→
 73→        const projectRecord = item.project
 74→          ? await resolveWorkspaceProjectRecord({
 75→              surreal: deps.surreal,
 76→              workspaceRecord: context.workspaceRecord,
 77→              projectInput: item.project,
 78→            })
 79→          : undefined;
 80→
 81→        const candidates = await searchEntitiesByEmbedding({
 82→          surreal: deps.surreal,
 83→          workspaceRecord: context.workspaceRecord,
 84→          queryEmbedding: embedding,
 85→          kinds: [item.kind],
 86→          ...(projectRecord ? { projectRecord } : {}),
 87→          limit: 5,
 88→        });
 89→
 90→        const top = candidates[0];
 91→        if (!top) {
 92→          suggestions.push(suggestion);
 93→          continue;
 94→        }
 95→
 96→        const normalizedTopStatus = top.status ? top.status.trim().toLowerCase() : undefined;
 97→        if (normalizedTopStatus && CLOSED_STATUSES.has(normalizedTopStatus)) {
 98→          suggestions.push(suggestion);
 99→          continue;
100→        }
101→
102→        if (top.score > 0.97) {
103→          discarded.push({
104→            title: item.title,
105→            reason: `Exact duplicate of existing item ${top.kind}:${top.id} (${top.name})`,
106→          });
107→          continue;
108→        }
109→
110→        if (top.score >= 0.8) {
111→          updated.push({
112→            existing_id: `${top.kind}:${top.id}`,
113→            title: top.name,
114→            changes: `Merge context from suggested item '${item.title}'`,
115→          });
116→          continue;
117→        }
118→
119→        suggestions.push(suggestion);
120→      }
121→
122→      return {
123→        suggestions,
124→        updated,
125→        discarded,
126→      };
127→    },
128→  });
129→}
