  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import { tool } from "ai";
  4→import { z } from "zod";
  5→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../../shared/contracts";
  6→import { createEmbeddingVector } from "../../graph/embeddings";
  7→import {
  8→  createExtractionProvenanceEdge,
  9→  createProjectRecord,
 10→  resolveWorkspaceProjectRecord,
 11→} from "../../graph/queries";
 12→import { seedDescriptionEntry } from "../../descriptions/persist";
 13→import { fireDescriptionUpdates } from "../../descriptions/triggers";
 14→import { ensureProjectFeatureEdge } from "../../workspace/workspace-scope";
 15→import { requireToolContext } from "../../chat/tools/helpers";
 16→import type { ChatToolDeps } from "../../chat/tools/types";
 17→
 18→export function createCreateWorkItemTool(deps: ChatToolDeps & { extractionModel: any }) {
 19→  return tool({
 20→    description:
 21→      "Create a task, feature, or project directly in the knowledge graph. Use when the user explicitly requests creation (\"add a task for X\") or during onboarding entity seeding. For uncertain/brainstormed items, prefer suggest_work_items instead.",
 22→    inputSchema: z.object({
 23→      kind: z.enum(["task", "feature", "project"]).describe(
 24→        "task: concrete executable work with action verb. feature: capability/requirement within a project. project: named top-level workstream.",
 25→      ),
 26→      title: z.string().min(1).describe("Concise entity title"),
 27→      rationale: z.string().min(1).describe("Why this entity is needed — seeds the description"),
 28→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Category classification"),
 29→      priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important, needs attention soon. medium: normal priority. low: nice-to-have, deferred."),
 30→      project: z.string().optional().describe("Project name to scope the entity under"),
 31→    }),
 32→    execute: async (input, options) => {
 33→      const context = requireToolContext(options);
 34→      const now = new Date();
 35→
 36→      const embedding = await createEmbeddingVector(
 37→        deps.embeddingModel,
 38→        input.title,
 39→        deps.embeddingDimension,
 40→      );
 41→
 42→      const entityId = randomUUID();
 43→
 44→      if (input.kind === "project") {
 45→        const projectRecord = await createProjectRecord({
 46→          surreal: deps.surreal,
 47→          name: input.title,
 48→          status: "active",
 49→          now,
 50→          workspaceRecord: context.workspaceRecord,
 51→          sourceMessageRecord: context.currentMessageRecord,
 52→        });
 53→
 54→        if (embedding) {
 55→          await deps.surreal.update(projectRecord).merge({ embedding });
 56→        }
 57→
 58→        void seedDescriptionEntry({
 59→          surreal: deps.surreal,
 60→          targetRecord: projectRecord,
 61→          text: input.rationale,
 62→        }).catch(() => undefined);
 63→
 64→        await createExtractionProvenanceEdge({
 65→          surreal: deps.surreal,
 66→          sourceRecord: context.currentMessageRecord,
 67→          targetRecord: projectRecord,
 68→          now,
 69→          confidence: 0.95,
 70→          model: deps.extractionModelId,
 71→          fromText: input.title,
 72→          evidence: context.latestUserText,
 73→          evidenceSourceRecord: context.currentMessageRecord,
 74→        });
 75→
 76→        return {
 77→          entity_id: `project:${projectRecord.id as string}`,
 78→          kind: "project" as const,
 79→          title: input.title,
 80→        };
 81→      }
 82→
 83→      if (input.kind === "task") {
 84→        const taskRecord = new RecordId("task", entityId);
 85→        await deps.surreal.create(taskRecord).content({
 86→          title: input.title,
 87→          status: "open",
 88→          workspace: context.workspaceRecord,
 89→          ...(input.category ? { category: input.category } : {}),
 90→          ...(input.priority ? { priority: input.priority } : {}),
 91→          ...(embedding ? { embedding } : {}),
 92→          created_at: now,
 93→          updated_at: now,
 94→        });
 95→
 96→        if (input.project) {
 97→          try {
 98→            const projectRecord = await resolveWorkspaceProjectRecord({
 99→              surreal: deps.surreal,
100→              workspaceRecord: context.workspaceRecord,
101→              projectInput: input.project,
102→            });
103→            await deps.surreal
104→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
105→                added_at: now,
106→              })
107→              .output("after");
108→          } catch {
109→            // project resolution is best-effort
110→          }
111→        }
112→
113→        void seedDescriptionEntry({
114→          surreal: deps.surreal,
115→          targetRecord: taskRecord,
116→          text: input.rationale,
117→        }).catch(() => undefined);
118→
119→        await createExtractionProvenanceEdge({
120→          surreal: deps.surreal,
121→          sourceRecord: context.currentMessageRecord,
122→          targetRecord: taskRecord,
123→          now,
124→          confidence: 0.95,
125→          model: deps.extractionModelId,
126→          fromText: input.title,
127→          evidence: context.latestUserText,
128→          evidenceSourceRecord: context.currentMessageRecord,
129→        });
130→
131→        return {
132→          entity_id: `task:${entityId}`,
133→          kind: "task" as const,
134→          title: input.title,
135→        };
136→      }
137→
138→      // feature
139→      const featureRecord = new RecordId("feature", entityId);
140→      await deps.surreal.create(featureRecord).content({
141→        name: input.title,
142→        status: "active",
143→        ...(input.category ? { category: input.category } : {}),
144→        ...(embedding ? { embedding } : {}),
145→        created_at: now,
146→        updated_at: now,
147→      });
148→
149→      if (input.project) {
150→        try {
151→          const projectRecord = await resolveWorkspaceProjectRecord({
152→            surreal: deps.surreal,
153→            workspaceRecord: context.workspaceRecord,
154→            projectInput: input.project,
155→          });
156→          await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
157→
158→          void fireDescriptionUpdates({
159→            surreal: deps.surreal,
160→            extractionModel: deps.extractionModel,
161→            trigger: {
162→              kind: "feature_created",
163→              entity: featureRecord,
164→              summary: `Feature added: ${input.title}`,
165→            },
166→          }).catch(() => undefined);
167→        } catch {
168→          // project resolution is best-effort
169→        }
170→      }
171→
172→      void seedDescriptionEntry({
173→        surreal: deps.surreal,
174→        targetRecord: featureRecord,
175→        text: input.rationale,
176→      }).catch(() => undefined);
177→
178→      await createExtractionProvenanceEdge({
179→        surreal: deps.surreal,
180→        sourceRecord: context.currentMessageRecord,
181→        targetRecord: featureRecord,
182→        now,
183→        confidence: 0.95,
184→        model: deps.extractionModelId,
185→        fromText: input.title,
186→        evidence: context.latestUserText,
187→        evidenceSourceRecord: context.currentMessageRecord,
188→      });
189→
190→      return {
191→        entity_id: `feature:${entityId}`,
192→        kind: "feature" as const,
193→        title: input.title,
194→      };
195→    },
196→  });
197→}
