21→      const context = requireToolContext(options);
22→
23→      return runPmAgent({
24→        deps,
25→        context,
26→        intent: input.intent,
27→        conversationContext: input.context,
28→        ...(input.project ? { project: input.project } : {}),
29→      });
30→    },
31→  });
32→}
